/// <summary>
/// Joins time part strings with the specified separator.
/// </summary>
private static string ConcatenateTimeSpanParts(
    List<string?> timeSpanParts, CultureInfo culture, string collectionSeparator)
{
    // Parts are already non-null after SetPrecisionOfTimeSpan filtering
    if (timeSpanParts.Count == 0)
    {
        return "no time";
    }

    if (timeSpanParts.Count == 1)
    {
        return timeSpanParts[0]!;
    }

    var allButLast = string.Join(collectionSeparator, timeSpanParts.Take(timeSpanParts.Count - 1));
    return $"{allButLast} and {timeSpanParts[^1]}";
}

