private static readonly string[] UnitNamesSingular = BuildUnitNames(plural: false);
private static readonly string[] UnitNamesPlural = BuildUnitNames(plural: true);

private static string[] BuildUnitNames(bool plural)
{
    var values = Enum.GetValues<TimeUnit>();
    var names = new string[values.Length];
    foreach (var u in values)
        names[(int)u] = u.ToString().ToLowerInvariant() + (plural ? "s" : "");
    return names;
