1. using System.Globalization;
2. 
3. namespace Textualizer;
4. 
5. /// <summary>
6. /// Specifies the unit of time for humanization purposes.
7. /// Values are ordered from largest to smallest.
8. /// </summary>
9. public enum TimeUnit
10. {
11.     /// <summary>Years.</summary>
12.     Year,
13.     /// <summary>Months.</summary>
14.     Month,
15.     /// <summary>Weeks.</summary>
16.     Week,
17.     /// <summary>Days.</summary>
18.     Day,
19.     /// <summary>Hours.</summary>
20.     Hour,
21.     /// <summary>Minutes.</summary>
22.     Minute,
23.     /// <summary>Seconds.</summary>
24.     Second,
25.     /// <summary>Milliseconds.</summary>
26.     Millisecond
27. }
28. 
29. /// <summary>
30. /// Provides extension methods for converting <see cref="TimeSpan"/> values to
31. /// human-readable strings with configurable precision, culture, and unit ranges.
32. /// </summary>
33. public static class TimeSpanReadabilityExtensions
34. {
35.     private const int DaysInAWeek = 7;
36.     private const double DaysInAYear = 365.2425;
37.     private const double DaysInAMonth = DaysInAYear / 12;
38. 
39.     private static readonly TimeUnit[] TimeUnits =
40.     [
41.         TimeUnit.Millisecond, TimeUnit.Second, TimeUnit.Minute, TimeUnit.Hour,
42.         TimeUnit.Day, TimeUnit.Week, TimeUnit.Month, TimeUnit.Year
43.     ];
44. 
45.     /// <summary>
46.     /// Converts a <see cref="TimeSpan"/> to a human-readable string.
47.     /// </summary>
48.     /// <param name="timeSpan">The time span to humanize.</param>
49.     /// <param name="precision">The number of time units to include (e.g., 2 for "1 hour, 30 minutes").</param>
50.     /// <param name="culture">The culture for localized formatting. Uses current culture if null.</param>
51.     /// <param name="maxUnit">The largest time unit to display.</param>
52.     /// <param name="minUnit">The smallest time unit to display.</param>
53.     /// <param name="collectionSeparator">The separator between time parts (default: ", ").</param>
54.     /// <param name="countEmptyUnits">Whether empty units count toward precision.</param>
55.     /// <returns>A human-readable string representation of the time span.</returns>
56.     /// <example>
57.     /// <code>
58.     /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
59.     /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
60.     /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
61.     /// </code>
62.     /// </example>
63.     public static string Humanize(
64.         this TimeSpan timeSpan,
65.         int precision = 1,
66.         CultureInfo? culture = null,
67.         TimeUnit maxUnit = TimeUnit.Year,
68.         TimeUnit minUnit = TimeUnit.Millisecond,
69.         string? collectionSeparator = null,
70.         bool countEmptyUnits = false)
71.     {
72.         culture ??= CultureInfo.CurrentCulture;
73. 
74.         var timeParts = CreateTimeParts(timeSpan, maxUnit, minUnit, culture);
75. 
76.         if (IsContainingOnlyNullValue(timeParts))
77.         {
78.             return "no time";
79.         }
80. 
81.         timeParts = SetPrecisionOfTimeSpan(timeParts, precision, countEmptyUnits);
82. 
83.         return ConcatenateTimeSpanParts(timeParts, culture, collectionSeparator ?? ", ");
84.     }
85. 
86.     /// <summary>
87.     /// Breaks down a TimeSpan into its component time part strings for each unit
88.     /// between maxUnit and minUnit.
89.     /// </summary>
90.     private static List<string?> CreateTimeParts(
91.         TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, CultureInfo culture)
92.     {
93.         var timeParts = new List<string?>(8);
94.         var totalDays = Math.Abs(timeSpan.TotalDays);
95.         var totalHours = Math.Abs(timeSpan.TotalHours);
96.         var totalMinutes = Math.Abs(timeSpan.TotalMinutes);
97.         var totalSeconds = Math.Abs(timeSpan.TotalSeconds);
98.         var totalMilliseconds = Math.Abs(timeSpan.TotalMilliseconds);
99. 
100.         foreach (var unit in TimeUnits)
101.         {
102.             if (unit < minUnit || unit > maxUnit)
103.             {
104.                 continue;
105.             }
106. 
107.             var value = unit switch
108.             {
109.                 TimeUnit.Year => (int)(totalDays / DaysInAYear),
110.                 TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
111.                 TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
112.                 TimeUnit.Day => (int)(totalDays % DaysInAWeek),
113.                 TimeUnit.Hour => timeSpan.Hours,
114.                 TimeUnit.Minute => timeSpan.Minutes,
115.                 TimeUnit.Second => timeSpan.Seconds,
116.                 TimeUnit.Millisecond => timeSpan.Milliseconds,
117.                 _ => 0
118.             };
119. 
120.             timeParts.Add(value != 0 ? FormatTimePart(value, unit, culture) : null);
121.         }
122. 
123.         return timeParts;
124.     }
125. 
126.     private static bool IsContainingOnlyNullValue(List<string?> timeParts)
127.     {
128.         for (int i = 0; i < timeParts.Count; i++)
129.         {
130.             if (timeParts[i] != null) return false;
131.         }
132.         return true;
133.     }
134. 
135.     /// <summary>
136.     /// Filters and limits time parts to the requested precision.
137.     /// </summary>
138.     private static List<string?> SetPrecisionOfTimeSpan(
139.         List<string?> timeParts, int precision, bool countEmptyUnits)
140.     {
141.         var result = new List<string?>(precision);
142.         int counted = 0;
143.         for (int i = 0; i < timeParts.Count && counted < precision; i++)
144.         {
145.             if (countEmptyUnits)
146.             {
147.                 counted++;
148.                 if (timeParts[i] != null)
149.                     result.Add(timeParts[i]);
150.             }
151.             else
152.             {
153.                 if (timeParts[i] != null)
154.                 {
155.                     result.Add(timeParts[i]);
156.                     counted++;
157.                 }
158.             }
159.         }
160.         return result;
161.     }
162. 
163.     /// <summary>
164.     /// Joins time part strings with the specified separator.
165.     /// </summary>
166.     private static string ConcatenateTimeSpanParts(
167.         List<string?> timeSpanParts, CultureInfo culture, string collectionSeparator)
168.     {
169.         // Parts are already non-null after SetPrecisionOfTimeSpan filtering
170.         if (timeSpanParts.Count == 0)
171.         {
172.             return "no time";
173.         }
174. 
175.         if (timeSpanParts.Count == 1)
176.         {
177.             return timeSpanParts[0]!;
178.         }
179. 
180.         var allButLast = string.Join(collectionSeparator, timeSpanParts.Take(timeSpanParts.Count - 1));
181.         return $"{allButLast} and {timeSpanParts[^1]}";
182.     }
183. 
184.     private static readonly string[] UnitNamesSingular = BuildUnitNames(plural: false);
185.     private static readonly string[] UnitNamesPlural = BuildUnitNames(plural: true);
186. 
187.     private static string[] BuildUnitNames(bool plural)
188.     {
189.         var values = Enum.GetValues<TimeUnit>();
190.         var names = new string[values.Length];
191.         foreach (var u in values)
192.             names[(int)u] = u.ToString().ToLowerInvariant() + (plural ? "s" : "");
193.         return names;
194.     }
195. 
196.     private static string FormatTimePart(int value, TimeUnit unit, CultureInfo culture)
197.     {
198.         var unitName = value == 1 ? UnitNamesSingular[(int)unit] : UnitNamesPlural[(int)unit];
199.         return $"{value} {unitName}";
200.     }
201. }
202. 
203. /// <summary>
204. /// Defines the contract for formatting a collection of items into a human-readable string.
205. /// </summary>
206. public interface ICollectionFormatter
207. {
208.     /// <summary>
209.     /// Formats a collection into a human-readable string using the default separator.
210.     /// </summary>
211.     /// <typeparam name="T">The type of items in the collection.</typeparam>
212.     /// <param name="collection">The collection to format.</param>
213.     /// <returns>A human-readable string representation of the collection.</returns>
214.     string Humanize<T>(IEnumerable<T> collection);
215. 
216.     /// <summary>
217.     /// Formats a collection using a custom object formatter and default separator.
218.     /// </summary>
219.     string Humanize<T>(IEnumerable<T> collection, Func<T, string?> objectFormatter);
220. 
221.     /// <summary>
222.     /// Formats a collection using a custom separator.
223.     /// </summary>
224.     string Humanize<T>(IEnumerable<T> collection, string separator);
225. }
226. 
227. /// <summary>
228. /// Default collection formatter that joins items with "and" for the last element.
229. /// Supports custom separators and object formatters.
230. /// </summary>
231. public class DefaultCollectionFormatter(string defaultSeparator) : ICollectionFormatter
232. {
233.     /// <summary>
234.     /// Gets the default separator used between collection items.
235.     /// </summary>
236.     protected string DefaultSeparator = defaultSeparator;
237. 
238.     /// <inheritdoc />
239.     public virtual string Humanize<T>(IEnumerable<T> collection) =>
240.         Humanize(collection, o => o?.ToString(), DefaultSeparator);
241. 
242.     /// <inheritdoc />
243.     public virtual string Humanize<T>(IEnumerable<T> collection, Func<T, string?> objectFormatter) =>
244.         Humanize(collection, objectFormatter, DefaultSeparator);
245. 
246.     /// <summary>
247.     /// Formats a collection using an object-returning formatter.
248.     /// </summary>
249.     public string Humanize<T>(IEnumerable<T> collection, Func<T, object?> objectFormatter) =>
250.         Humanize(collection, objectFormatter, DefaultSeparator);
251. 
252.     /// <inheritdoc />
253.     public virtual string Humanize<T>(IEnumerable<T> collection, string separator) =>
254.         Humanize(collection, o => o?.ToString(), separator);
255. 
256.     /// <summary>
257.     /// Core formatting method that converts a collection to a human-readable string.
258.     /// </summary>
259.     public virtual string Humanize<T>(
260.         IEnumerable<T> collection, Func<T, string?> objectFormatter, string separator)
261.     {
262.         ArgumentNullException.ThrowIfNull(collection);
263.         ArgumentNullException.ThrowIfNull(objectFormatter);
264. 
265.         return HumanizeDisplayStrings(collection, objectFormatter, separator);
266.     }
267. 
268.     /// <summary>
269.     /// Formats with an object-returning formatter, converting via .ToString().
270.     /// </summary>
271.     public string Humanize<T>(
272.         IEnumerable<T> collection, Func<T, object?> objectFormatter, string separator)
273.     {
274.         ArgumentNullException.ThrowIfNull(collection);
275.         ArgumentNullException.ThrowIfNull(objectFormatter);
276. 
277.         // Fuse the two Select calls into a single pass
278.         return HumanizeDisplayStrings(collection, item => objectFormatter(item)?.ToString(), separator);
279.     }
280. 
281.     private string HumanizeDisplayStrings<T>(
282.         IEnumerable<T> source, Func<T, string?> formatter, string separator)
283.     {
284.         var items = new List<string>();
285.         foreach (var element in source)
286.         {
287.             var formatted = formatter(element);
288.             if (formatted != null)
289.             {
290.                 var trimmed = formatted.Trim();
291.                 if (trimmed.Length > 0)
292.                     items.Add(trimmed);
293.             }
294.         }
295. 
296.         if (items.Count == 0)
297.         {
298.             return string.Empty;
299.         }
300. 
301.         if (items.Count == 1)
302.         {
303.             return items[0];
304.         }
305. 
306.         var allButLast = string.Join(separator, items.Take(items.Count - 1));
307.         return $"{allButLast} and {items[^1]}";
308.     }
309. }
310. 
311. /// <summary>
312. /// Provides extension methods for transforming strings with params-based transformer chains.
313. /// </summary>
314. public static class TransformExtensions
315. {
316.     /// <summary>
317.     /// Transforms a string using a single transformer (avoids params array allocation).
318.     /// </summary>
319.     public static string Transform(
320.         this string input, CultureInfo culture, IStringTransformer transformer) =>
321.         transformer.Transform(input);
322. 
323.     /// <summary>
324.     /// Transforms a string using the provided transformers, applied in order.
325.     /// </summary>
326.     /// <param name="input">The string to transform.</param>
327.     /// <param name="culture">The culture for culture-sensitive transformations.</param>
328.     /// <param name="transformers">One or more transformers to apply sequentially.</param>
329.     /// <returns>The transformed string.</returns>
330.     public static string Transform(
331.         this string input, CultureInfo culture, params IStringTransformer[] transformers)
332.     {
333.         for (int i = 0; i < transformers.Length; i++)
334.             input = transformers[i].Transform(input);
335.         return input;
336.     }
337. }
